<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">    temp</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">=</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">qb[t]</span></span>
